/* css reset*/
*{box-sizing: border-box;margin: 0; padding: 0;}
ul,ol{list-style: none;}
*::before,*::after{box-sizing: border-box;}
a{ color: inherit; text-decoration: none;}
img{max-width: 100%;max-height: 100%;}
input{outline:none;}

/* style*/
body{ background:#fff;}
.globalHeader{
    margin:50px 50px 0 50px ;
}
@media(min-width:500px){
    .globalHeader{
        margin:140px 30px 0 30px ;
    }
}
p{
    font-size: 80px;
    text-align: center;
    padding-bottom:30px;
}
.searchForm {
    display: flex;
    justify-content: space-between;
    
}
@media (min-width:500px) {
    .searchForm{
        max-width: 400px;
        margin-left: auto;
        margin-right: auto;
    }
}

.searchForm > input{ 
    width: 100%;
    height: 44px;
    padding: 0 10px;
    border: none;
    border: 1px solid #ddd;
    border-radius: 10px 0 0 10px;
 }
.searchForm > button{  
    white-space: nowrap;
    padding: 0 15px;
    border: none;
    border-radius: 0 10px 10px 0;
    background: #7E9BEA;
    color: #fff;
    font-size: 17px;
}
.globalMain{ 
    max-width: 800px;
    margin-left: auto;
    margin-right: auto;
  
}
.siteList{ 
    display: flex;
    flex-wrap: wrap;
    margin: 50px;
    justify-content: space-between;
    
}
@media(min-width:500px){
    .siteList{
        margin-left: 0;
        margin-right: -25.6px;
        justify-content: flex-start;
    }
}
.siteList > li{ 
    margin-bottom: 10px;
}
@media(min-width:500px){
    .siteList> li{
        margin-right: 25.6px;
    }
}
.siteList .site{ 
    width: 112px;
    display: flex;
    justify-content: center;
    align-items: center;
    flex-direction: column;
    background: #fff;
    border-radius: 4px;
    padding: 15px 0;
    position: relative;
    cursor: pointer;
}
.siteList .site > .loge{ 
    width: 48px;
    height: 48px;
    margin-top: 7px;
    display: flex;
    justify-content: center;
    align-items: center;
    font-size: 30px;
    text-transform: uppercase;
    background-color: #F1F3F4;
    border-radius: 50%;
    
}
.siteList .site > .link{
    font-size: 13px;
    margin-top: 15px;

}
.siteList .site > .close {
    position: absolute;
    right: 1px;
    top: 1px;
    width: 23px;
    height: 23px;
    background-color: #F1F3F4;
    border-radius: 50%;
    cursor: default;
    display: none;
}
.siteList .site:hover > .close{
    display: block;
}
.siteList .addButton { 
    width: 112px;
    display: flex;
    justify-content: center;
    align-items: center;
    flex-direction: column;
    background: #fff;
    padding: 22px 0;
    border-radius: 4px;
}
.siteList .addButton .icon{ 
    width: 48px;
    height: 48px;
    background-color: #F1F3F4;
    border-radius: 50%;
}
.siteList .addButton .text{
    font-size: 11px;
    margin: 15px 0 -8px 0;
}
.siteList .site:hover,.siteList .addButton:hover{
    background-color: #E8E8E9;
}
